let dadosRebanho = { numAnimais: 0, estrutura: '', sistemaCriacao: '', estado: '', vacinas: [], cios: [] };
let dadosSuinos = { numAnimais: 0, tipoCriacao: '', vacinas: [], cios: [] };
let dadosAves = { numAves: 0, tipoInstalacao: '', tipoProducao: '' };
let dadosAvesVacinas = [];
let dadosOvelhas = { numAnimais: 0, tipoCriacao: '', vacinas: [] };
let dadosCabras = { numAnimais: 0, tipoCriacao: '', vacinas: [] };
let dadosCavalos = { numAnimais: 0, tipoCriacao: '', vacinas: [], cios: [] };
let tamanhoFonte = 16, leitorAtivo = null;

// ACESSIBILIDADE
function toggleAcessibilidade() { document.getElementById('menuAcessibilidade').classList.toggle('ativo'); }
function aumentarFonte() { tamanhoFonte += 2; if (tamanhoFonte > 24) tamanhoFonte = 24; aplicarTamanhoFonte(); salvarPreferencias(); }
function diminuirFonte() { tamanhoFonte -= 2; if (tamanhoFonte < 12) tamanhoFonte = 12; aplicarTamanhoFonte(); salvarPreferencias(); }
function aplicarTamanhoFonte() { document.querySelectorAll('body, button, input, select, textarea, label, p, h1, h2, h3, h4, h5, li, td, th').forEach(el => el.style.fontSize = tamanhoFonte + 'px'); }
function toggleContraste() { document.body.classList.toggle('modo-escuro'); document.getElementById('btnContraste').innerHTML = document.body.classList.contains('modo-escuro') ? '☀️ Modo Claro' : '🌓 Modo Escuro'; salvarPreferencias(); }
function iniciarLeitura() { pararLeitura(); if ('speechSynthesis' in window) { const t = document.querySelector('.tela.ativa'); if (t) { const f = new SpeechSynthesisUtterance(t.innerText); f.lang = 'pt-BR'; f.rate = 0.9; window.speechSynthesis.speak(f); leitorAtivo = f; } } }
function pararLeitura() { if ('speechSynthesis' in window) { window.speechSynthesis.cancel(); leitorAtivo = null; } }
function salvarPreferencias() { localStorage.setItem('pref', JSON.stringify({ tamanhoFonte, modoEscuro: document.body.classList.contains('modo-escuro') })); }
function carregarPreferencias() { const p = JSON.parse(localStorage.getItem('pref')); if (p) { if (p.tamanhoFonte) { tamanhoFonte = p.tamanhoFonte; aplicarTamanhoFonte(); } if (p.modoEscuro) { document.body.classList.add('modo-escuro'); document.getElementById('btnContraste').innerHTML = '☀️ Modo Claro'; } } dadosRebanho.vacinas = JSON.parse(localStorage.getItem('vacinasRebanho') || '[]'); dadosRebanho.cios = JSON.parse(localStorage.getItem('ciosRebanho') || '[]'); dadosSuinos.vacinas = JSON.parse(localStorage.getItem('vacinasSuinos') || '[]'); dadosSuinos.cios = JSON.parse(localStorage.getItem('ciosSuinos') || '[]'); dadosAvesVacinas = JSON.parse(localStorage.getItem('vacinasAves') || '[]'); dadosOvelhas.vacinas = JSON.parse(localStorage.getItem('vacinasOvelhas') || '[]'); dadosCabras.vacinas = JSON.parse(localStorage.getItem('vacinasCabras') || '[]'); dadosCavalos.vacinas = JSON.parse(localStorage.getItem('vacinasCavalos') || '[]'); dadosCavalos.cios = JSON.parse(localStorage.getItem('ciosCavalos') || '[]'); }
function svL() { localStorage.setItem('vacinasRebanho', JSON.stringify(dadosRebanho.vacinas)); }
function scL() { localStorage.setItem('ciosRebanho', JSON.stringify(dadosRebanho.cios)); }
function svS() { localStorage.setItem('vacinasSuinos', JSON.stringify(dadosSuinos.vacinas)); }
function scS() { localStorage.setItem('ciosSuinos', JSON.stringify(dadosSuinos.cios)); }
function svA() { localStorage.setItem('vacinasAves', JSON.stringify(dadosAvesVacinas)); }
function svO() { localStorage.setItem('vacinasOvelhas', JSON.stringify(dadosOvelhas.vacinas)); }
function svC() { localStorage.setItem('vacinasCabras', JSON.stringify(dadosCabras.vacinas)); }
function svCa() { localStorage.setItem('vacinasCavalos', JSON.stringify(dadosCavalos.vacinas)); }
function scCa() { localStorage.setItem('ciosCavalos', JSON.stringify(dadosCavalos.cios)); }

function mostrarTela(id) { document.querySelectorAll('.tela').forEach(t => t.classList.remove('ativa')); document.getElementById(id).classList.add('ativa'); }
function selecionarProducao(tipo) { mostrarTela(tipo === 'agro' ? 'telaAgro' : tipo === 'leite' ? 'telaLeite' : tipo === 'suinos' ? 'telaSuinos' : tipo === 'ovelhas' ? 'telaOvelhas' : tipo === 'cabras' ? 'telaCabras' : tipo === 'cavalos' ? 'telaCavalos' : 'telaAves'); }
function voltarInicio() { mostrarTela('telaInicial'); }
function ftL() { document.getElementById('secaoVacinas').style.display = 'none'; document.getElementById('secaoCio').style.display = 'none'; document.getElementById('secaoHigieneTetos').style.display = 'none'; }
function ftS() { document.getElementById('secaoVacinasSuinos').style.display = 'none'; document.getElementById('secaoReproducaoSuinos').style.display = 'none'; }
function ftA() { document.getElementById('secaoVacinasAves').style.display = 'none'; }
function ftCa() { document.getElementById('secaoVacinasCavalos').style.display = 'none'; document.getElementById('secaoReproducaoCavalos').style.display = 'none'; }

function fd(d) { if (d instanceof Date && !isNaN(d)) return d.toLocaleDateString('pt-BR'); if (typeof d === 'string') { const dt = new Date(d + 'T00:00:00'); if (!isNaN(dt)) return dt.toLocaleDateString('pt-BR'); const p = d.split('/'); if (p.length === 3) { const db = new Date(p[2], p[1]-1, p[0]); if (!isNaN(db)) return db.toLocaleDateString('pt-BR'); } } return d || 'Data inválida'; }

// ========== AGRICULTURA ==========
document.getElementById('formAgro').addEventListener('submit', function(e) {
    e.preventDefault();
    const l = document.getElementById('localizacao').value, m = document.getElementById('tipoManejo').value, cultura = document.getElementById('culturaSelecionada').value;
    const imp = []; document.querySelectorAll('.check-implemento:checked').forEach(c => imp.push(c.value));
    document.getElementById('recomendacoesAgro').innerHTML = `<h4>📌 Informações:</h4><ul><li>📍 ${l}</li><li>🌿 Manejo: ${m}</li><li>🌾 Cultura: ${cultura}</li></ul>`;
    if (cultura) { document.getElementById('manejoCultura').innerHTML = gerarManejoCultura(cultura); document.getElementById('manejoCultura').style.display = 'block'; }
    document.getElementById('manutencaoMaquinas').style.display = imp.length > 0 ? 'block' : 'none';
    if (imp.length > 0) document.getElementById('manutencaoMaquinas').innerHTML = gerarManutencao(imp);
    document.getElementById('descarteAgrotoxicos').innerHTML = '<h4>⚠️ Descarte de Agrotóxicos:</h4><ul><li>1️⃣ Tríplice Lavagem</li><li>2️⃣ Perfurar embalagens</li><li>3️⃣ Devolver em posto de coleta</li><li>4️⃣ Local coberto e ventilado</li><li>5️⃣ Usar EPIs</li></ul>';
    document.getElementById('resultadoAgro').style.display = 'block';
});

function gerarManutencao(imp) {
    let h = '<h3>🔧 Manutenção dos Implementos</h3>';
    if (imp.includes('trator')) h += '<div class="maquina-card"><h4>🚜 Trator</h4><ul><li><strong>10h:</strong> Checar óleo</li><li><strong>50h:</strong> Graxar</li><li><strong>250-500h:</strong> Trocar óleo/filtros</li></ul></div>';
    if (imp.includes('colheitadeira')) h += '<div class="maquina-card"><h4>🌾 Colheitadeira</h4><ul><li><strong>10h:</strong> Soprar poeira</li><li><strong>50h:</strong> Lubrificar</li><li><strong>Pós-safra:</strong> Lavar</li></ul></div>';
    if (imp.includes('pulverizador')) h += '<div class="maquina-card"><h4>💨 Pulverizador</h4><ul><li><strong>10h:</strong> Circular água</li><li><strong>50h:</strong> Limpar filtro</li></ul></div>';
    if (imp.includes('plantadeira')) h += '<div class="maquina-card"><h4>🌱 Plantadeira</h4><ul><li><strong>Diária:</strong> Limpar dosadores</li><li><strong>Pós-safra:</strong> Lavar adubo</li></ul></div>';
    if (imp.includes('semeadeira')) h += '<div class="maquina-card"><h4>🌾 Semeadeira</h4><ul><li><strong>Diária:</strong> Limpar condutores</li><li><strong>Pós-safra:</strong> Proteger</li></ul></div>';
    if (imp.includes('grade')) h += '<div class="maquina-card"><h4>⚙️ Grade</h4><ul><li><strong>Diária:</strong> Graxar</li><li><strong>Pós-safra:</strong> Anticorrosivo</li></ul></div>';
    return h + '<p style="margin-top:15px;color:#e65100;"><strong>💡 Consulte o manual do fabricante.</strong></p>';
}

function gerarManejoCultura(cultura) {
    let h = '<h3>📖 Manejo Completo</h3>';
    if (cultura === 'soja') { h += '<div class="cultura-card"><h4>🌱 Soja</h4><ul><li>Pré-plantio: Dessecação 15-20d. Plantio Direto.</li><li>Plantio: Semeadora precisão. 3-5cm. Adubo base.</li><li>Desenvolvimento: Bradyrhizobium. Monitorar lagartas/percevejos.</li><li>Colheita: Colhedora. Umidade 13-15%.</li></ul></div>'; h += gerarMIP('soja'); }
    else if (cultura === 'milho') { h += '<div class="cultura-card"><h4>🌽 Milho</h4><ul><li>Plantio: Semeadora-adubadeira. Nitrogênio cobertura.</li><li>Desenvolvimento: Nitrogênio 4-6 folhas. Lagarta-do-cartucho.</li><li>Colheita: Colhedora. Umidade 14-18%.</li></ul></div>'; h += gerarMIP('milho'); }
    else if (cultura === 'trigo') { h += '<div class="cultura-card"><h4>🌾 Trigo</h4><ul><li>Plantio: Semeadeira contínua. Nitrogênio cobertura.</li><li>Desenvolvimento: Nitrogênio perfilhamento. Fungicidas.</li><li>Colheita: Colhedora. Umidade 13-15%.</li></ul></div>'; h += gerarMIP('trigo'); }
    else if (cultura === 'feijao') { h += '<div class="cultura-card"><h4>🫘 Feijão</h4><ul><li>Plantio: Semeadora precisão. Ciclo 70-90d.</li><li>Desenvolvimento: Irrigação. Mosca-branca.</li><li>Colheita: Manual/mecanizada.</li></ul></div>'; h += gerarMIP('feijao'); }
    else if (cultura === 'mandioca') { h += '<div class="cultura-card"><h4>🥔 Mandioca</h4><ul><li>Plantio: Manivas em sulcos. 1m x 0,6m.</li><li>Desenvolvimento: Controle mato 5 meses.</li><li>Colheita: Arranquio 12-24 meses.</li></ul></div>'; h += gerarMIP('mandioca'); }
    else if (cultura === 'cana') { h += '<div class="cultura-card"><h4>🎋 Cana</h4><ul><li>Plantio: Toletes em sulcos.</li><li>Desenvolvimento: Controle daninhas. 12-18m.</li><li>Colheita: Mecanizada.</li></ul></div>'; h += gerarMIP('cana'); }
    else if (cultura === 'cafe') { h += '<div class="cultura-card"><h4>☕ Café</h4><ul><li>Plantio: Mudas em covas. 3m x 1m.</li><li>Desenvolvimento: Podas. Roçadas.</li><li>Colheita: Manual/derriçadora.</li></ul></div>'; h += gerarMIP('cafe'); }
    else if (cultura === 'ervamate') { h += '<div class="cultura-card"><h4>🍃 Erva-Mate</h4><ul><li>Plantio: Mudas. Sombreamento.</li><li>Desenvolvimento: Podas. Roçadas.</li><li>Colheita: Poda 18-24 meses.</li></ul></div>'; h += gerarMIP('ervamate'); }
    else if (cultura === 'laranja') { h += '<div class="cultura-card"><h4>🍊 Laranja</h4><ul><li>Plantio: Mudas enxertadas certificadas. 6m x 3m.</li><li>Desenvolvimento: Adubação NPK. Poda ramos ladrões.</li><li>Colheita: Manual. Indústria: arrancamento. Mesa: tesoura.</li></ul></div>'; h += gerarMIP('laranja'); }
    else if (cultura === 'limao') { h += '<div class="cultura-card"><h4>🍋 Limão Taiti</h4><ul><li>Plantio: Mudas enxertadas certificadas.</li><li>Desenvolvimento: Adubação NPK. Poda ramos ladrões.</li><li>Colheita: Manual com tesoura.</li></ul></div>'; h += gerarMIP('limao'); }
    else if (cultura === 'uva') { h += '<div class="cultura-card"><h4>🍇 Uva</h4><ul><li>Plantio: Mudas enxertadas. Latada (mesa) ou Espaldeira (vinho).</li><li>Desenvolvimento: Poda inverno. Desbrota/desfolha. Raleio bagas.</li><li>Colheita: Manual tesoura. Cachos direto na caixa.</li></ul></div>'; h += gerarMIP('uva'); }
    else if (cultura === 'banana') { h += '<div class="cultura-card"><h4>🍌 Banana</h4><ul><li>Plantio: Mudas rizoma. Covas profundas.</li><li>Desenvolvimento: Desbaste (Mãe+Filha+Neta). Corte coração.</li><li>Colheita: Cacho inteiro verde. Climatização.</li></ul></div>'; h += gerarMIP('banana'); }
    else if (cultura === 'morango') { h += '<div class="cultura-card"><h4>🍓 Morango</h4><ul><li>Plantio: Mudas estolões. Mulching ou semi-hidropônico.</li><li>Desenvolvimento: Gotejamento. Fertirrigação. Limpeza folhas velhas.</li><li>Colheita: Manual contínua (2-3x/semana).</li></ul></div>'; h += gerarMIP('morango'); }
    else if (cultura === 'pessego') { h += '<div class="cultura-card"><h4>🍑 Pêssego</h4><ul><li>Plantio: Inverno. Mudas enxertadas. Espaldeira.</li><li>Desenvolvimento: Poda inverno/verão. Raleio frutos.</li><li>Colheita: Manual. Fundo verde→amarelo.</li></ul></div>'; h += gerarMIP('pessego'); }
    else if (cultura === 'maca') { h += '<div class="cultura-card"><h4>🍎 Maçã</h4><ul><li>Plantio: Inverno. Mudas enxertadas. Horas frio.</li><li>Desenvolvimento: Poda inverno/verão. Raleio.</li><li>Colheita: Manual. Frutos firmes.</li></ul></div>'; h += gerarMIP('maca'); }
    else if (cultura === 'ameixa') { h += '<div class="cultura-card"><h4>🟣 Ameixa</h4><ul><li>Plantio: Inverno. Mudas enxertadas.</li><li>Desenvolvimento: Poda inverno/verão. Raleio.</li><li>Colheita: Manual. Frutos firmes.</li></ul></div>'; h += gerarMIP('ameixa'); }
    else if (cultura === 'bergamota') { h += '<div class="cultura-card"><h4>🍊 Bergamota</h4><ul><li>Plantio: Mudas certificadas. Covas adubadas.</li><li>Desenvolvimento: Adubação NPK. Poda copa.</li><li>Colheita: Manual tesoura. Cortar pedúnculo.</li></ul></div>'; h += gerarMIP('bergamota'); }
    else if (cultura === 'abacaxi') { h += '<div class="cultura-card"><h4>🍍 Abacaxi</h4><ul><li>Plantio: Mudas coroa/filhote. Linhas duplas.</li><li>Desenvolvimento: Indução floral (carbureto/ethephon).</li><li>Colheita: Manual. Base amarelando.</li></ul></div>'; h += gerarMIP('abacaxi'); }
    else if (cultura === 'cebola') { h += '<div class="cultura-card"><h4>🧅 Cebola</h4><ul><li>Plantio: Transplante mudas.</li><li>Desenvolvimento: Controle daninhas.</li><li>Colheita: 70% folhas estalam. Cura campo.</li></ul></div>'; h += gerarMIP('cebola'); }
    else if (cultura === 'batata') { h += '<div class="cultura-card"><h4>🥔 Batata</h4><ul><li>Plantio: Batata-semente sulcos.</li><li>Desenvolvimento: Amontoa (20cm).</li><li>Colheita: Dessecar rama. Arranquio.</li></ul></div>'; h += gerarMIP('batata'); }
    return h;
}

function gerarMIP(cultura) {
    let pragas = '';
    if (cultura === 'soja') pragas = 'Lagarta-da-soja, percevejo-marrom, mosca-branca';
    else if (cultura === 'milho') pragas = 'Lagarta-do-cartucho, pulgão, cigarrinha';
    else if (cultura === 'trigo') pragas = 'Pulgão, lagarta-do-trigo, percevejo';
    else if (cultura === 'feijao') pragas = 'Mosca-branca, ácaro-rajado, vaquinha';
    else if (cultura === 'mandioca') pragas = 'Mandarová, percevejo-de-renda, ácaros';
    else if (cultura === 'cana') pragas = 'Broca-da-cana, cigarrinha, cupim';
    else if (cultura === 'cafe') pragas = 'Broca-do-café, bicho-mineiro, ácaro-vermelho';
    else if (cultura === 'ervamate') pragas = 'Broca-da-erva-mate, ácaros, cochonilhas';
    else if (cultura === 'laranja') pragas = 'Cigarrinha-do-citros (Greening), bicho-furão, cochonilhas';
    else if (cultura === 'limao') pragas = 'Cigarrinha-do-citros (Greening), bicho-furão, cochonilhas';
    else if (cultura === 'uva') pragas = 'Pérola-da-terra, tripes, ácaros';
    else if (cultura === 'banana') pragas = 'Broca-da-bananeira (Moleque), trips, nematoides';
    else if (cultura === 'morango') pragas = 'Ácaro-rajado, broca-do-colo, pulgão';
    else if (cultura === 'pessego') pragas = 'Mosca-das-frutas, mariposa-oriental, ácaro-vermelho';
    else if (cultura === 'maca') pragas = 'Mosca-das-frutas, mariposa-oriental, ácaro-vermelho';
    else if (cultura === 'ameixa') pragas = 'Mosca-das-frutas, mariposa-oriental, pulgões';
    else if (cultura === 'bergamota') pragas = 'Cigarrinha-dos-citros (Greening), ácaro-da-falsa-ferrugem';
    else if (cultura === 'abacaxi') pragas = 'Cochonilha-do-abacaxi, broca-do-fruto';
    else if (cultura === 'cebola') pragas = 'Tripes, mosca-da-cebola';
    else if (cultura === 'batata') pragas = 'Vaquinha (larva-alfinete), pulgões, tripes';
    let h = '<div class="cultura-card" style="border-left-color:#ff6f00;"><h4>🐛 Manejo Integrado de Pragas (MIP)</h4>';
    h += `<p style="color:#666;margin-bottom:10px;"><strong>Principais pragas:</strong> ${pragas}</p>`;
    h += '<h4>📋 1. Monitoramento</h4><ul><li><strong>Pano de Batida:</strong> Sacudir plantas sobre pano branco.</li><li><strong>Armadilhas:</strong> Coloridas ou de feromônio.</li><li><strong>Inspeção Visual:</strong> Olhar parte de baixo das folhas.</li></ul>';
    h += '<h4>📊 2. Nível de Dano Econômico</h4><ul><li>Só controlar quando população atingir limite de prejuízo.</li></ul>';
    h += '<h4>🛡️ 3. Métodos de Controle</h4><ul><li><strong>Cultural:</strong> Vazio sanitário, rotação, destruição restos.</li><li><strong>Biológico:</strong> Vespinhas Trichogramma, joaninhas, fungo Beauveria, Bt.</li><li><strong>Genético:</strong> Plantas Bt com área de refúgio.</li><li><strong>Químico (último caso):</strong> Produtos seletivos, rotação ativos.</li></ul>';
    if (cultura === 'laranja' || cultura === 'limao') { h += '<h4>🍊 Pragas dos Citros</h4><ul><li><strong>Cigarrinha-do-citros:</strong> Transmite Greening. Controle: vespinha Tamarixia + armadilhas amarelas. Erradicar!</li><li><strong>Bicho-furão:</strong> Lagarta entra no fruto. Controle: catar frutos caídos + Trichogramma.</li></ul>'; }
    if (cultura === 'uva') { h += '<h4>🍇 Pragas da Uva</h4><ul><li><strong>Pérola-da-terra:</strong> Cochonilha suga raízes. Controle: mudas sadias + porta-enxertos resistentes.</li><li><strong>Tripes:</strong> Ataca flores e frutos jovens. Controle: monitoramento brotação + defensivos seletivos.</li></ul>'; }
    if (cultura === 'banana') { h += '<h4>🍌 Pragas da Banana</h4><ul><li><strong>Broca-da-bananeira (Moleque):</strong> Larvas cavam túneis no rizoma. Controle: iscas sanduíche + Beauveria bassiana.</li></ul>'; }
    if (cultura === 'morango') { h += '<h4>🍓 Pragas do Morango</h4><ul><li><strong>Ácaro-rajado:</strong> Suga folhas. Controle: ácaros predadores.</li><li><strong>Broca-do-colo:</strong> Lagarta broca base. Controle: mudas sadias + fungos benéficos.</li></ul>'; }
    if (cultura === 'pessego' || cultura === 'maca' || cultura === 'ameixa') { h += '<h4>🍑 Pragas de Frutíferas Temperadas</h4><ul><li><strong>Mosca-das-frutas:</strong> Fura fruto. Controle: armadilhas + ensacamento.</li><li><strong>Mariposa-oriental:</strong> Ataca ponteiros. Controle: feromônio + biológico.</li></ul>'; }
    if (cultura === 'bergamota') { h += '<h4>🍊 Pragas da Bergamota</h4><ul><li><strong>Cigarrinha:</strong> Transmite Greening. Controle: Tamarixia + armadilhas.</li><li><strong>Ácaro-da-falsa-ferrugem:</strong> Casca escura. Controle: enxofre + acaricidas.</li></ul>'; }
    if (cultura === 'abacaxi') { h += '<h4>🍍 Pragas do Abacaxi</h4><ul><li><strong>Cochonilha:</strong> Suga seiva. Controle: controlar formigas + tratar mudas.</li></ul>'; }
    if (cultura === 'cebola') { h += '<h4>🧅 Pragas da Cebola</h4><ul><li><strong>Tripes:</strong> Raspam folhas. Controle: inseticidas seletivos.</li></ul>'; }
    if (cultura === 'batata') { h += '<h4>🥔 Pragas da Batata</h4><ul><li><strong>Vaquinha:</strong> Larva fura batatas. Controle: rotação + tratamento sulco.</li><li><strong>Pulgões:</strong> Transmitem viroses. Controle: monitoramento.</li></ul>'; }
    h += '<div class="alerta-vacina"><strong>⚠️ Tecnologia de Aplicação:</strong> Evitar vento >10km/h e calor >30°C. Regular bicos e pressão.</div></div>';
    return h;
}

// ========== PECUÁRIA LEITEIRA ==========
document.getElementById('formLeite').addEventListener('submit', function(e) { e.preventDefault(); dadosRebanho.numAnimais = parseInt(document.getElementById('numAnimais').value); dadosRebanho.estrutura = document.getElementById('estrutura').value; dadosRebanho.sistemaCriacao = document.getElementById('sistemaCriacao').value; dadosRebanho.estado = document.getElementById('estado').value; aiL(); mH(); mA(); document.getElementById('resultadoLeite').style.display = 'block'; });
function aiL() { document.getElementById('infoRebanho').innerHTML = `<p>🐮 Total: <strong>${dadosRebanho.numAnimais}</strong></p><p>🏗️: <strong>${dadosRebanho.estrutura}</strong></p><p>🏠: <strong>${dadosRebanho.sistemaCriacao}</strong></p><p>📍: <strong>${dadosRebanho.estado}</strong></p><p>💉 Vacinas: <strong>${dadosRebanho.vacinas.length}</strong></p><p>📅 Cios: <strong>${dadosRebanho.cios.length}</strong></p>`; }
function mA() { const s = dadosRebanho.sistemaCriacao; let h = '<h3>🍽️ Alimentação</h3>'; if (s === 'confinamento') h += '<div class="higiene-card"><h4>🏭 Confinamento</h4><ul><li>TMR: Silagem + concentrado.</li></ul></div>'; else if (s === 'semi') h += '<div class="higiene-card"><h4>🏡 Semi-Confinamento</h4><ul><li>60-70% Volumoso.</li></ul></div>'; else if (s === 'pasto') h += '<div class="higiene-card"><h4>🌿 Pasto</h4><ul><li>80-90% Volumoso.</li></ul></div>'; document.getElementById('alimentacaoLeite').innerHTML = h; }
