function vp(idCio) { document.querySelectorAll('#corpoTabelaCios tr').forEach(l=>l.classList.remove('linha-selecionada')); const ln=document.getElementById('linha-cio-'+idCio); if(ln) ln.classList.add('linha-selecionada'); const cio=dadosRebanho.cios.find(c=>c.id===idCio); if(!cio) return; let dc; if(cio.data.includes('/')){const p=cio.data.split('/');dc=new Date(p[2],p[1]-1,p[0]);}else{dc=new Date(cio.data+'T00:00:00');} if(isNaN(dc.getTime())){alert('Data inválida!');return;} if(cio.hora&&cio.hora!=='Não informada'){const[hh,mm]=cio.hora.split(':');dc.setHours(hh,mm,0,0);} const hj=new Date(); hj.setHours(0,0,0,0); const d=d=>Math.ceil((d.getTime()-hj.getTime())/86400000); const f=d=>{const a=String(d.getDate()).padStart(2,'0'),b=String(d.getMonth()+1).padStart(2,'0');return`${a}/${b}/${d.getFullYear()}`;}; const s=(d,t)=>{if(d>0)return`⏳ Faltam ${d} dias`;if(d===0)return t==='parto'?'🎉 Hoje!':'✅ Hoje';return t==='parto'?`🐮 Nasceu há ${Math.abs(d)} dias`:'✅ Concluído';}; let tp='',tl=''; if(cio.tipoCobertura==='inseminacao'){tl='🧬 IA'; const ins=new Date(dc.getTime()); ins.setHours(ins.getHours()+12); const dg=new Date(ins.getTime()); dg.setDate(dg.getDate()+30); const rp=new Date(ins.getTime()); rp.setDate(rp.getDate()+210); const pp=new Date(ins.getTime()); pp.setDate(pp.getDate()+240); const pt=new Date(ins.getTime()); pt.setDate(pt.getDate()+270); tp=`<div class="topico topico-cio"><span class="icone-topico">🔵</span><div class="conteudo-topico"><strong>Cio:</strong> ${f(dc)}<br><small>${s(d(dc),'cio')}</small></div></div><div class="topico topico-inseminacao"><span class="icone-topico">🟢</span><div class="conteudo-topico"><strong>IA:</strong> ${f(ins)}<br><small>12h | ${s(d(ins),'ins')}</small></div></div><div class="topico topico-diagnostico"><span class="icone-topico">🔬</span><div class="conteudo-topico"><strong>Diagnóstico:</strong> ${f(dg)}<br><small>30d | ${s(d(dg),'diag')}</small></div></div><div class="topico topico-repouso"><span class="icone-topico">🟡</span><div class="conteudo-topico"><strong>Repouso:</strong> ${f(rp)}<br><small>60d antes | ${s(d(rp),'rep')}</small></div></div><div class="topico topico-preparto"><span class="icone-topico">🟠</span><div class="conteudo-topico"><strong>Pré-Parto:</strong> ${f(pp)}<br><small>30d antes | ${s(d(pp),'pre')}</small></div></div><div class="topico topico-parto"><span class="icone-topico">🔴</span><div class="conteudo-topico"><strong>Parto:</strong> ${f(pt)}<br><small>270d | ${s(d(pt),'parto')}</small></div></div>`;} else{tl='🐂 Monta'; const dg=new Date(dc.getTime()); dg.setDate(dg.getDate()+30); const rp=new Date(dc.getTime()); rp.setDate(rp.getDate()+210); const pp=new Date(dc.getTime()); pp.setDate(pp.getDate()+240); const pt=new Date(dc.getTime()); pt.setDate(pt.getDate()+270); tp=`<div class="topico topico-cio"><span class="icone-topico">🔵</span><div class="conteudo-topico"><strong>Cio: Cobertura</strong><br>${f(dc)}<br><small>Monta | ${s(d(dc),'cobertura')}</small></div></div><div class="topico topico-diagnostico"><span class="icone-topico">🔬</span><div class="conteudo-topico"><strong>Diagnóstico:</strong> ${f(dg)}<br><small>30d | ${s(d(dg),'diag')}</small></div></div><div class="topico topico-repouso"><span class="icone-topico">🟡</span><div class="conteudo-topico"><strong>Repouso:</strong> ${f(rp)}<br><small>60d antes | ${s(d(rp),'rep')}</small></div></div><div class="topico topico-preparto"><span class="icone-topico">🟠</span><div class="conteudo-topico"><strong>Pré-Parto:</strong> ${f(pp)}<br><small>30d antes | ${s(d(pp),'pre')}</small></div></div><div class="topico topico-parto"><span class="icone-topico">🔴</span><div class="conteudo-topico"><strong>Parto:</strong> ${f(pt)}<br><small>270d | ${s(d(pt),'parto')}</small></div></div>`;} document.getElementById('periodosReprodutivos').innerHTML=`<h4>📊 Períodos</h4><div class="animal-selecionado">🐄 Brinco Nº <strong>${cio.brinco}</strong> | ${f(dc)} | ${tl}</div><div class="topicos-reprodutivos">${tp}</div>`; }
